mapper.select:
SELECT * FROM ( SELECT inner_q.project_id, inner_q.project_title, inner_q.project_describe, inner_q.project_identifier, inner_q.status, inner_q.start_date, inner_q.finish_date, inner_q.created_at, ROWNUM AS RN FROM ( SELECT p.project_id, p.project_title, p.project_describe, p.project_identifier, c.default_describe AS status, p.start_date, p.finish_date, p.created_at FROM project p LEFT JOIN common_code c ON p.status = c.common_id AND c.common_code = '0J'
p.project_title LIKE '%' || #{keyword} || '%'
ORDER BY p.project_id DESC ) inner_q WHERE ROWNUM <= #{offset} + #{pageSize} ) WHERE RN > #{offset}

SELECT COUNT(*)
FROM project
WHERE project_identifier = #{projectIdentifier}

SELECT module_name
FROM module_mapping
WHERE project_id = #{projectId}

mapper.insert:
INSERT INTO module_mapping( module_map_id, project_id, module_name ) SELECT (SELECT NVL(MAX(module_map_id), 0) FROM module_mapping) + ROWNUM, t.project_id, t.module_name FROM (
SELECT #{projectId} AS project_id, #{name} AS module_name FROM dual
) t
